import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class SecureXSSExample {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Encoding user input using ESAPI to prevent XSS attacks
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        // Outputting encoded user input to the webpage
        System.out.println("<div>" + encodedUserInput + "</div>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
